def checkReverse(arr, n):
    # base case: n == 1
    if n == 1:
        return True
    # find the first element that is not in descending order
    # this is the pivot point
    i = 1
    while i < n and arr[i-1] < arr[i]:
        i += 1
    # if all elements are in descending order, return True
    if i == n:
        return True
    # find the first element that is not in ascending order
    # after the pivot point
    j = i
    while arr[j] < arr[j-1]:
        if i > 1 and arr[j] < arr[i-2]:
            return False
        j += 1
    # if all elements are in ascending order, return True
    if j == n:
        return True
    # find the first element that is not in descending order
    # after the pivot point
    k = j
    if arr[k] < arr[i-1]:
        return False
    while k > 1 and k < n:
        if arr[k] < arr[k-1]:
            return False
        k += 1
    return True

