def countTransformation(a, b):
    # size of strings
    n = len(a)
    m = len(b)
    # if b is empty
    if m == 0:
        return 1
    # dp table
    dp = [[0 for _ in range(n + 1)] for _ in range(m + 1)]
    # if j == 0
    for i in range(m):
        if i == 0:
            if a[0] == b[0]:
                dp[i][0] = 1
            else:
                dp[i][0] = 0
        else:
            if a[0] == b[i]:
                dp[i][0] = dp[i - 1][0] + 1
            else:
                dp[i][0] = dp[i - 1][0]
    # if i == 0
    for j in range(1, n + 1):
        if a[j - 1] == b[0]:
            dp[0][j] = dp[0][j - 1] + 1
        else:
            dp[0][j] = dp[0][j - 1]
    # i, j > 0
    for i in range(1, m + 1):
        for j in range(1, n + 1):
            if a[j - 1] == b[i - 1]:
                dp[i][j] = dp[i][j - 1] + dp[i - 1][j - 1]
            else:
                dp[i][j] = dp[i][j - 1]
    return dp[m][n]

