def isMultipleOf3(n):
    # Initialize the count of odd and even numbers.
    odd_count = 0
    even_count = 0
    # If the input number is negative, convert it to positive.
    if n < 0:
        n = -n
    # If the input number is 0 or 1, return 1.
    if n == 0 or n == 1:
        return 1
    # While the input number is non-zero,
    while n:
        # If the input number is odd, increment the count of odd numbers.
        if n & 1:
            odd_count += 1
        # If the input number is even, increment the count of even numbers.
        if n & 2:
            even_count += 1
        # Shift the input number right by 2 bits.
        n >>= 2
    # Call the function recursively with the absolute difference of odd and even counts.
    return isMultipleOf3(abs(odd_count - even_count))

